    int ViewDroppedViewers( const TOOL_EVENT& aEvent );

    int Refresh( const TOOL_EVENT& aEvent );
    int UpdateMenu( const TOOL_EVENT& aEvent );

    int ShowPlayer( const TOOL_EVENT& aEvent );
