173	
174	void UPDATE_MANAGER::CheckForUpdate( wxWindow* aNoticeParent, bool aManual )
175	{
176	    if( m_working )
177	    {
178	        wxLogTrace( wxS( "UPDATE" ), wxS( "CheckForUpdate skipped: previous check still running" ) );
179	
180	        if( aManual )
181	        {
182	            aNoticeParent->CallAfter(
183	                    [aNoticeParent]()
184	                    {
185	                        wxMessageBox( _( "An update check is already in progress." ),
186	                                      _( "Check for Updates" ),
187	                                      wxOK | wxICON_INFORMATION, aNoticeParent );
188	                    } );
189	        }
190	        return;
191	    }
192	
193	    m_working = true;
194	
195	    m_updateBackgroundJob = Pgm().GetBackgroundJobMonitor().Create( _( "Update Check" ) );
196	
197	    auto update_check = [aNoticeParent, aManual, this]() -> void
198	    {
199	        std::shared_ptr<BACKGROUND_JOB_REPORTER> reporter = m_updateBackgroundJob->m_reporter;
200	
201	        std::stringstream update_json_stream;
202	        std::stringstream request_json_stream;
203	
204	        wxString aUrl = UPDATE_QUERY_ENDPOINT;
205	        reporter->SetNumPhases( 1 );
206	        reporter->Report( _( "Requesting update info" ) );
207	
208	        UPDATE_REQUEST requestContent;
209	
210	
211	        // These platform keys are specific to the downloads site
212	#if defined( __WXMSW__ )
213	        requestContent.platform = "windows";
214	
215	    #if defined( KICAD_BUILD_ARCH_X64 )
216	        requestContent.arch = "amd64";
217	    #elif defined( KICAD_BUILD_ARCH_X86 )
218	        requestContent.arch = "i686";
219	    #elif defined( KICAD_BUILD_ARCH_ARM )
220	        requestContent.arch = "arm";
221	    #elif defined( KICAD_BUILD_ARCH_ARM64 )
222	        requestContent.arch = "arm64";
223	    #endif
224	#elif defined( __WXOSX__ )
225	        requestContent.platform = "macos";
226	        requestContent.arch = "unified";
227	#else
228	        //everything else gets lumped as linux
229	        requestContent.platform = "linux";
230	        requestContent.arch = "";
231	#endif
232	        wxString verString = GetZeoVersion();
233	        verString.Replace( "~", "-" ); // make the string valid for semver
234	        requestContent.current_version = verString;
235	        requestContent.lang = Pgm().GetLanguageTag();
236	
237	        KICAD_SETTINGS* settings = GetAppSettings<KICAD_SETTINGS>( "kicad" );
238	
239	        requestContent.last_check = settings->m_lastUpdateCheckTime;
240	
241	        nlohmann::json requestJson = nlohmann::json( requestContent );
242	        request_json_stream << requestJson;
243	
244	        wxLogTrace( wxS( "UPDATE" ),
245	                    wxS( "POST %s  current=%s  last_received=%s  manual=%d" ), aUrl,
246	                    requestContent.current_version, settings->m_lastReceivedUpdate,
247	                    aManual ? 1 : 0 );
248	
249	        int responseCode = PostRequest( aUrl, request_json_stream.str(), &update_json_stream,
250	                                        reporter.get(), 20480 );
251	
252	        wxLogTrace( wxS( "UPDATE" ), wxS( "Update check responseCode=%d" ), responseCode );
253	
254	        // Check that the response is 200 (content provided)
255	        // We can also return 204 for no update
256	        if( responseCode == 200 && !Pgm().m_Quitting )
257	        {
258	            nlohmann::json  update_json;
259	            UPDATE_RESPONSE response;
260	            bool            parsed = false;
261	
262	            try
263	            {
264	                update_json_stream >> update_json;
265	                response = update_json.get<UPDATE_RESPONSE>();
266	                parsed = true;
267	            }
268	            catch( const std::exception& e )
269	            {
270	                wxLogError( wxString::Format( _( "Unable to parse update response: %s" ), e.what() ) );
271	
272	                if( aManual && !Pgm().m_Quitting )
273	                {
274	                    wxString errMsg = wxString::Format(
275	                            _( "Unable to parse update response from server: %s" ), e.what() );
276	                    aNoticeParent->CallAfter(
277	                            [aNoticeParent, errMsg]()
278	                            {
279	                                if( Pgm().m_Quitting )
280	                                    return;
281	
282	                                wxMessageBox( errMsg, _( "Check for Updates" ),
283	                                              wxOK | wxICON_ERROR, aNoticeParent );
284	                            } );
285	                }
286	            }
287	
288	            if( parsed && !Pgm().m_Quitting )
