import { createClient } from "@supabase/supabase-js";
import { getSupabasePublicEnv } from "./supabase-config";

export type Platform = "mac" | "linux" | "windows";

export interface VersionInfo {
  version: string;
  platforms: Platform[];
}

const RELEASES_BUCKET = "zeo-releases";

const FILE_NAME_FOR: Record<Platform, (version: string) => string> = {
  mac: (v) => `zeo-${v}.dmg`,
  linux: (v) => `zeo-${v}-x86_64.AppImage`,
  windows: (v) => `zeo-${v}-x86_64.exe`,
};

const SEMVER_RE = /^\d+\.\d+\.\d+$/;

export function isValidVersion(version: string): boolean {
  return SEMVER_RE.test(version);
}

export function fileNameFor(platform: Platform, version: string): string {
  return FILE_NAME_FOR[platform](version);
}

function compareSemverDesc(a: string, b: string): number {
  const [aMaj, aMin, aPatch] = a.split(".").map(Number);
  const [bMaj, bMin, bPatch] = b.split(".").map(Number);
  return bMaj - aMaj || bMin - aMin || bPatch - aPatch;
}

export async function listAvailableVersions(): Promise<VersionInfo[]> {
  const env = getSupabasePublicEnv();
  if (!env) return [];

  const supabase = createClient(env.url, env.anonKey);

  const { data: rootEntries, error } = await supabase.storage
    .from(RELEASES_BUCKET)
    .list("", { limit: 1000 });

  if (error || !rootEntries) return [];

  const versionFolders = rootEntries
    .filter((entry) => entry.id === null && SEMVER_RE.test(entry.name))
    .map((entry) => entry.name);

  const allPlatforms = Object.keys(FILE_NAME_FOR) as Platform[];

  const versions = await Promise.all(
    versionFolders.map(async (version): Promise<VersionInfo> => {
      const { data: files } = await supabase.storage
        .from(RELEASES_BUCKET)
        .list(version, { limit: 100 });

      if (!files) return { version, platforms: [] };

      const presentNames = new Set(files.map((f) => f.name));
      const platforms = allPlatforms.filter((p) =>
        presentNames.has(FILE_NAME_FOR[p](version))
      );

      return { version, platforms };
    })
  );

  return versions
    .filter((v) => v.platforms.length > 0)
    .sort((a, b) => compareSemverDesc(a.version, b.version));
}

