import { NextRequest, NextResponse } from "next/server";
import { createClient } from "@supabase/supabase-js";
import { ZEO_VERSION } from "@/lib/constants";
import { fileNameFor, isValidVersion, type Platform } from "@/lib/downloads";

const BASE_URL = "https://auth.zeo.dev/storage/v1/object/public/zeo-releases";

const PLATFORMS = new Set<Platform>(["mac", "linux", "windows"]);

export async function GET(request: NextRequest) {
  const platform = request.nextUrl.searchParams.get("platform") as Platform | null;
  const version = request.nextUrl.searchParams.get("version") ?? ZEO_VERSION;

  if (!platform || !PLATFORMS.has(platform)) {
    return NextResponse.json({ error: "Invalid platform" }, { status: 400 });
  }

  if (!isValidVersion(version)) {
    return NextResponse.json({ error: "Invalid version" }, { status: 400 });
  }

  const fileUrl = `${BASE_URL}/${version}/${fileNameFor(platform, version)}`;

  const supabase = createClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.SUPABASE_SERVICE_ROLE_KEY!,
  );

  supabase.from("downloads").insert({
    platform,
    version,
    user_agent: request.headers.get("user-agent") ?? null,
  }).then();

  return NextResponse.redirect(fileUrl);
}

