  arch: string
  current_version: string
  lang: string
  last_check: string
}

// Launcher sends "macos" / "windows" / "linux"; storage helpers use "mac" / "windows" / "linux".
const PLATFORM_ALIAS: Record<string, Platform> = {
  macos: 'mac',
  mac: 'mac',
  windows: 'windows',
  win: 'windows',
  linux: 'linux',
}

function compareSemver(a: string, b: string): number {
  const cleanA = a.replace(/^v/, '')
  const cleanB = b.replace(/^v/, '')

  const partsA = cleanA.split(/[.\-]/).map(p => {
    const n = parseInt(p, 10)
    return isNaN(n) ? 0 : n
  })
  const partsB = cleanB.split(/[.\-]/).map(p => {
    const n = parseInt(p, 10)
    return isNaN(n) ? 0 : n
  })

  const len = Math.max(partsA.length, partsB.length)
  for (let i = 0; i < len; i++) {
    const numA = partsA[i] ?? 0
    const numB = partsB[i] ?? 0
    if (numA < numB) return -1
    if (numA > numB) return 1
  }
  return 0
}

export async function POST(request: NextRequest) {
  let body: UpdateRequest
  try {
    body = await request.json()
  } catch {
    return Response.json({ error: 'Invalid JSON body' }, { status: 400 })
  }

  const { current_version, platform: clientPlatform } = body
  if (!current_version || typeof current_version !== 'string') {
    return Response.json({ error: 'current_version is required' }, { status: 400 })
  }

  const platform = PLATFORM_ALIAS[(clientPlatform ?? '').toLowerCase()]
  if (!platform) {
    // Unknown platform — treat as "no update" rather than 400 so old/exotic
    // clients fail closed instead of seeing an error.
    return new Response(null, { status: 204 })
  }

  // Source of truth is the zeo-releases storage bucket. listAvailableVersions()
  // already enumerates version folders, checks which platform files are present,
  // and returns them sorted descending — so the highest entry with our platform's
  // file is the "latest available for this OS".
  const versions = await listAvailableVersions()
  const latestForPlatform = versions.find(v => v.platforms.includes(platform))

  if (!latestForPlatform) {
    return new Response(null, { status: 204 })
  }

  if (compareSemver(current_version, latestForPlatform.version) >= 0) {
    return new Response(null, { status: 204 })
  }

  const baseUrl = `${request.nextUrl.protocol}//${request.nextUrl.host}`
  return Response.json({
    version: latestForPlatform.version,
    release_date: '',
    details_url: `${baseUrl}/docs/changelog`,
    downloads_url: `${baseUrl}/download`,
  })
}

